#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
 pid_t pid;

 pid = fork();

 if (pid < 0) {
 printf("Fork failed!\n");
 return 1;
 }
 else if (pid == 0) {
 // Child process
 printf("Child: PID = %d, PPID = %d\n", getpid(), getppid());
 printf("Child executing...\n");
 _exit(0); // Child exits
 }
 else {
 // Parent process
 printf("Parent: PID = %d, Child PID = %d\n", getpid(), pid);
 wait(NULL); // Wait for child
 printf("Parent: Child has finished\n");
 }

 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
 pid_t pid;

 pid = fork();

 if (pid < 0) {
 printf("Fork failed\n");
 return 1;
 }
 else if (pid == 0) {
 // Child: execute 'ls' command
 printf("Child (PID %d): Calling exec()\n", getpid());
 execlp("/bin/ls", "ls", "-l", NULL);
 // If exec() succeeds, this won't execute
 printf("exec() failed\n");
 _exit(1);
 }
 else {
 // Parent waits for child
 wait(NULL);
 printf("Parent: Child finished execution\n");
 }

 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
 pid_t pid;

 pid = fork();

 if (pid < 0) {
 printf("Fork failed\n");
 return 1;
 }
 else if (pid == 0) {
 // Child exits immediately, becomes zombie
 printf("Child (PID %d): Exiting now\n", getpid());
 _exit(0); // Child terminates
 }
 else {
 // Parent doesn't call wait() - child becomes zombie
 printf("Parent (PID %d): Not waiting for child %d\n", getpid(), pid);
 printf("Child %d is now ZOMBIE\n", pid);
 sleep(10); // Parent sleeps, child remains zombie
 wait(NULL); // Now reap the zombie
 printf("Parent: Zombie reaped\n");
 }

 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
 pid_t pid1, pid2;

 printf("Original process: PID = %d\n", getpid());

 pid1 = fork();

 if (pid1 == 0) {
 // First child
 printf("First child: PID = %d, PPID = %d\n", getpid(), getppid());

 pid2 = fork(); // Create grandchild
 if (pid2 == 0) {
 // Grandchild
 printf("Grandchild: PID = %d, PPID = %d\n", getpid(), getppid());
 _exit(0);
 }
 _exit(0);
 }
 else {
 // Original parent waits for first child
 wait(NULL);
 printf("Parent: All children finished\n");
 }

 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <string.h>

int main() {
 int pipefd[2];
 pid_t pid;
 char msg[] = "Hello from parent!";
 char buffer[50];

 if (pipe(pipefd) == -1) {
 perror("pipe");
 return 1;
 }

 pid = fork();

 if (pid == 0) {
 // Child: reads from pipe
 close(pipefd[1]); // Close write end
 read(pipefd[0], buffer, sizeof(buffer));
 printf("Child received: %s\n", buffer);
 close(pipefd[0]);
 _exit(0);
 }
 else {
 // Parent: writes to pipe
 close(pipefd[0]); // Close read end
 write(pipefd[1], msg, strlen(msg) + 1);
 close(pipefd[1]);
 wait(NULL);
 printf("Parent: Message sent to child\n");
 }

 return 0;
}
